import React, {

  useEffect,
  useState

} from 'react';

import ResumeService from '../services/ResumeService';

function AllResumes() {

  const [resumes, setResumes] = useState([]);

  const [editingId, setEditingId] =
    useState(null);

  const [editedResume, setEditedResume] =
    useState({});

  // ================= LOAD =================

  useEffect(() => {

    fetchResumes();

  }, []);

  const fetchResumes = async () => {

    try {

      const response =
        await ResumeService.getAllResumes();

      setResumes(response.data);

    } catch (error) {

      console.log(error);

      alert(
        'Failed To Load Resumes'
      );
    }
  };

  // ================= DELETE =================

  const deleteResume = async (id) => {

    try {

      await ResumeService.deleteResume(id);

      alert(
        'Resume Deleted Successfully'
      );

      fetchResumes();

    } catch (error) {

      console.log(error);

      alert(
        'Delete Failed'
      );
    }
  };

  // ================= EDIT =================

  const startEdit = (resume) => {

    setEditingId(resume.id);

    setEditedResume({

      ...resume

    });
  };

  // ================= CHANGE =================

  const handleChange = (e) => {

    setEditedResume({

      ...editedResume,

      [e.target.name]:
        e.target.value

    });
  };

  // ================= UPDATE =================

  const updateResume = async () => {

    try {

      await ResumeService.updateResume(

        editingId,

        editedResume

      );

      alert(
        'Resume Updated Successfully'
      );

      setEditingId(null);

      fetchResumes();

    } catch (error) {

      console.log(error);

      alert(
        'Update Failed'
      );
    }
  };

  return (

    <div className="container mt-5 mb-5">

      <h1 className="mb-4">

        All Resumes

      </h1>

      {

        resumes.length === 0 ? (

          <h4>No Resume Found</h4>

        ) : (

          resumes.map((resume) => (

            <div
              className="card shadow p-4 mb-4"
              key={resume.id}
            >

              {

                editingId === resume.id ? (

                  // ================= EDIT MODE =================

                  <div>

                    <input
                      type="text"
                      name="fullName"
                      value={editedResume.fullName}
                      className="form-control mb-2"
                      onChange={handleChange}
                    />

                    <input
                      type="email"
                      name="email"
                      value={editedResume.email}
                      className="form-control mb-2"
                      onChange={handleChange}
                    />

                    <input
                      type="text"
                      name="phone"
                      value={editedResume.phone}
                      className="form-control mb-2"
                      onChange={handleChange}
                    />

                    <textarea
                      name="summary"
                      value={editedResume.summary}
                      className="form-control mb-2"
                      rows="4"
                      onChange={handleChange}
                    />

                    <input
                      type="text"
                      name="skills"
                      value={editedResume.skills}
                      className="form-control mb-3"
                      onChange={handleChange}
                    />

                    <button
                      className="btn btn-success me-2"
                      onClick={updateResume}
                    >

                      Save Update

                    </button>

                    <button
                      className="btn btn-secondary"
                      onClick={() =>
                        setEditingId(null)
                      }
                    >

                      Cancel

                    </button>

                  </div>

                ) : (

                  // ================= VIEW MODE =================

                  <div className="row">

                    <div className="col-md-3">

                      {

                        resume.profileImage && (

                          <img
                            src={resume.profileImage}
                            alt="Profile"
                            className="img-fluid rounded-circle"
                            style={{

                              width: '150px',
                              height: '150px',
                              objectFit: 'cover'

                            }}
                          />

                        )
                      }

                    </div>

                    <div className="col-md-9">

                      <h3>

                        {resume.fullName}

                      </h3>

                      <p>

                        <strong>Email:</strong>

                        {' '}

                        {resume.email}

                      </p>

                      <p>

                        <strong>Phone:</strong>

                        {' '}

                        {resume.phone}

                      </p>

                      <p>

                        <strong>Skills:</strong>

                        {' '}

                        {resume.skills}

                      </p>

                      <p>

                        <strong>Summary:</strong>

                        {' '}

                        {resume.summary}

                      </p>

                      <button
                        className="btn btn-primary me-2"
                        onClick={() =>
                          startEdit(resume)
                        }
                      >

                        Edit

                      </button>

                      <button
                        className="btn btn-danger"
                        onClick={() =>
                          deleteResume(
                            resume.id
                          )
                        }
                      >

                        Delete

                      </button>

                    </div>

                  </div>

                )
              }

            </div>

          ))
        )
      }

    </div>
  );
}

export default AllResumes;
